var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"밀어붙여라! 밀어붙여! 흡혈귀 놈들을 죽여라!","JPN":"追い込め！　追い込めろ！　吸血鬼のやつらを殺せ！","ENG":"Charge! Attack! Kill those vampire scum!","TWN":"衝上去！衝上去！殺死那些吸血鬼！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"놈들의 영지는 이제 우리의 땅이 될 것이다!","JPN":"やつらの領地はこれで我々のものだ！","ENG":"Their land will soon be ours!","TWN":"他們的領地將成為我們的土地！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"으아악!","JPN":"あああ！","ENG":"Aaah!","TWN":"啊啊啊！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"비켜! 뒤에 좀 비키라고!","JPN":"どけ！　後ろ、どけよ！","ENG":"Get out of the way! Let me through!","TWN":"讓開！往後退一點！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"부관! 병사들이 대체 왜 저러고 있지? 아까 전부터 전혀 앞으로 나아가지 못하고 있지 않나!","JPN":"副官！　兵士たちは何してるんだ？　さっきからまったく前へ進んでいないじゃないか！","ENG":"Hey! What are those soldiers doing?! Why aren’t they advancing forward?!","TWN":"副官！士兵們到底在幹什麼？從剛才開始怎麼就一動不動了啊！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"공작님! 그게… 고위 흡혈귀로 보이는 자 하나가 영지의 입구를 막고 있습니다.","JPN":"公爵！　それが……高位の吸血鬼らしき者が領地の入口を塞いでいます。","ENG":"Sir! Well... There seems to be a high-class vampire blocking the entrance.","TWN":"報告公爵！有…有一個看起來像是高階吸血鬼的傢伙擋在了領地入口。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"고위 흡혈귀라고? 이제 몇 마리 남지도 않은 족속이 스스로 전선까지 기어 나왔단 말인가? 그것도 혼자?","JPN":"高位の吸血鬼だと？　もう何匹も残っていない輩が、自ら戦線まで出てきやがったのか？　それも1人で？","ENG":"A high-class vampire? Those things are almost extinct, but one has decided to come out of its hole? And alone at that?","TWN":"高階吸血鬼？已經所剩無幾的族群竟然自己爬到前線來了？而且還是一個人？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"흐흐, 오히려 잘 됐어. 보물이 제 발로 걸어 들어온 셈이군.","JPN":"ふふ、むしろチャンスだ。宝物が自分の足でやってきたものだな。","ENG":"Keke... Excellent! My luck just keeps getting better!","TWN":"呵呵，正合我意。寶物自己送上門來了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"당장 놈의 심장을 뽑아서 내게 가져오도록.","JPN":"今すぐにやつの心臓を抜き取って私に持って来い。","ENG":"Bring me his heart!","TWN":"立刻把那傢伙的心臟挖出來帶給我。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"그것들을 풀어도 상관없다.","JPN":"あれを使っても構わん。","ENG":"I’ll allow using those savages.","TWN":"把那些傢伙放出來也無妨。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……わかりました。","ENG":"...Yes, sir.","TWN":"…遵命。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"전원, 전열 재정비! 선두는 괴수를 풀어라!","JPN":"全員、戦列を再整備しろ！　先頭は怪獣を出せ！","ENG":"All, change front formation! Put the beasts in front!","TWN":"全體聽令，整頓隊伍！在前線釋放怪物！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"흐음, 처음엔 야만스럽게 떼로 덤비시더니… 이번엔 길들인 야수종인가요?","JPN":"ふーん、最初は野蛮に群がって攻撃してきましたが……今度は躾けた野獣種ですか？","ENG":"Hmm... First, you charge in like barbarians... Now, you send in your tamed beasts?","TWN":"哼，一開始是成群撲上來…這次是被馴服的野獸種嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"정말이지. 재미있게 해주시는 분들이군요.","JPN":"まったく。退屈しない方々ですね。","ENG":"You people never cease to surprise me.","TWN":"真是的，終於有點意思了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"이, 이럴 수가… 고작 권총 하나로 괴수 무리를 전부 처치하다니 대체 어떻게?","JPN":"そ、そんな……ピストル1丁で怪獣の群れを全部倒すとは、いったいどうやって？","ENG":"I-I don’t believe it...! He killed all those beasts with just a revolver... How’s that even possible?","TWN":"這，這怎麼可能？！竟然用一把手槍就解決了所有怪物！到底是怎麼做到的？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"별 말씀을. 그저 가볍게 피하면서 급소만 노렸을 뿐이랍니다.","JPN":"ふふ、朝飯前でしたよ。ただ軽くよけながら急所を狙ったまでですから。","ENG":"Why, thank you. All I did was avoid their attacks and shoot for their weak spots.","TWN":"小意思，我只是輕鬆地閃避了幾下，然後瞄準要害開了幾槍而已。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"네놈! 감히 날 비웃는 거냐!","JPN":"貴様！　私をからかっているのか！","ENG":"How dare you mock me!","TWN":"你這傢伙！竟敢嘲諷我！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"잠깐, 그러고 보니 네 옷의 그 문장은 설마…… 프레데릭 가문?","JPN":"待て、そういえば貴様の服のその紋章、まさか……フレドレック家？","ENG":"Wait.. That crest on his clothes... Could it be the Frederick family?","TWN":"等一下，仔細一看，你衣服上的那個徽章，難道是…弗雷德里克家族的？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>결투자 프레데릭</color>이란 피도 눈물도 없다는 흡혈귀가…… 바로 너였나?!","JPN":"<color=#ffd34c>決闘者フレドレック</color>という血も涙もない吸血鬼とは……貴様のことだったのか！？","ENG":"So you’re the heartless vampire, <color=#ffd34c>Frederick the Duelist</color>!","TWN":"<color=#ffd34c>決鬥者弗雷德里克</color>那個沒血沒淚的吸血鬼…就是你嗎？！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 제 하찮은 이름을 바우어 공작께서 알고 계시다니 영광일 따름이군요.","JPN":"おっと、私のくだらない名前をバウアー公爵がご存じだったとは、光栄ですね。","ENG":"Oh my, it’s an honor for a person of your status to recognize a low-life like me, Duke Bower.","TWN":"哎呀，能讓鮑爾公爵知道我這微不足道的名字，真是榮幸之至啊。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"하, 하지만 내 라이칸스로프는 혼자서 성벽을 찢어발기는 괴물이다!","JPN":"だ、だが私のライカンスロープは1人で城壁を切り裂く化け物だ！","ENG":"B-but my lycanthropes are monsters that can tear down castle walls singlehandedly!","TWN":"但，但我的狼人可是能撕裂城牆的怪物啊！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BAAUER_NPC_NULL_NULL","text":{"KOREA":"게다가 지금은 보름달이 뜬 밤이지!","JPN":"しかも今夜は満月の夜！","ENG":"Plus, there’s a full moon tonight!","TWN":"而且今晚是月圓之夜！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};